async function main() {
  console.log(`🚀 Sincronizando ${dadosSuplementos.suplementos.length} suplementos comerciais no banco (Blindagem Ativa)...`);
  
  let totalProcessados = 0;

  for (const sup of dadosSuplementos.suplementos) {
    try {
      // Procura se já existe para evitar duplicidades
      const existe = await prisma.banco_equivale.findFirst({ 
        where: { Alimento: sup.Alimento } 
      });

      if (existe) {
        // Se já existe, atualiza os dados garantindo consistência
        await prisma.banco_equivale.update({
          where: { id: existe.id },
          data: {
            Energia__Kcal_: sup.Energia__Kcal_,
            grupo: "Suplementos"
          }
        });
      } else {
        // Se é novo, cria do zero
        await prisma.banco_equivale.create({ 
          data: {
            Alimento: sup.Alimento,
            Quantidade__g_: sup.Quantidade__g_,
            Energia__Kcal_: sup.Energia__Kcal_,
            grupo: "Suplementos"
          } 
        });
      }

      totalProcessados++;
      if (totalProcessados % 15 === 0) {
        console.log(`Progresso: ${totalProcessados} itens validados no banco...`);
      }
    } catch (e) {
      console.error(`Erro ao processar o item: ${sup.Alimento}`, e);
      continue;
    }
  }
  
  console.log(`\n🎉 Sincronização concluída com sucesso absoluto!`);
  console.log(`🔹 Total de suplementos gerenciados na tabela central: ${totalProcessados}`);
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
